#include <stdio.h>
#include <stdlib.h>
#define MAXN 100005
#define MAXM 100005
typedef struct Edge {
    int u, v;
} Edge;
int n, m;
Edge edges[MAXM];
int degrees[MAXN];
int count = 0;
void removeEdge(int i) {
    degrees[edges[i].u]--;
    degrees[edges[i].v]--;
}
void addEdge(int i, int u, int v) {
    degrees[u]++;
    degrees[v]++;
}
int isValid() {
    for (int i = 1; i <= n; i++) {
        if (degrees[i] < 0) return 0;
    }
    return 1;
}
void dfs(int u, int parent) {
    for (int i = 1; i <= m; i++) {
        if (edges[i].u == u && edges[i].v != parent) {
            dfs(edges[i].v, u);
        }
    }
}
int main() {
    scanf("%d %d", &n, &m);
    for (int i = 1; i <= m; i++) {
        scanf("%d %d", &edges[i].u, &edges[i].v);
        degrees[edges[i].u]++;
        degrees[edges[i].v]++;
    }
    for (int i = 1; i <= m; i++) {
        removeEdge(i);
        for (int j = 1; j <= n; j++) {
            for (int k = 1; k <= n; k++) {
                if (j != k && degrees[j] > 0 && degrees[k] > 0) {
                    addEdge(i, j, k);
                    if (isValid()) {
                        count++;
                    }
                    removeEdge(i);
                }
            }
        }
        addEdge(i, edges[i].u, edges[i].v);
    }
    printf("%d\n", count);
    return 0;
}

